import * as OntologyInterfaces from "@osdk/foundry.ontologies/OntologyInterface";
export async function loadInterfaceMetadata(client, objectType) {
  const r = await OntologyInterfaces.get(client, await client.ontologyRid, objectType, {
    preview: true,
    branch: client.branch
  });
  const {
    wireInterfaceTypeV2ToSdkObjectDefinition
  } = await import("@osdk/generator-converters");
  return wireInterfaceTypeV2ToSdkObjectDefinition(r, true);
}