import * as ActionTypesV2 from "@osdk/foundry.ontologies/ActionTypeV2";
export async function loadActionMetadata(client, actionType) {
  const r = await ActionTypesV2.get(client, await client.ontologyRid, actionType, {
    branch: client.branch
  });
  const {
    wireActionTypeV2ToSdkActionMetadata
  } = await import("@osdk/generator-converters");
  return wireActionTypeV2ToSdkActionMetadata(r);
}